import { BrowserWindow } from 'electron';
import { sshService } from '../SSHService';
import { BaseProvider, type ProviderScanContext } from './providers/BaseProvider';
import { RawVpsProvider } from './providers/RawVpsProvider';
import { CoolifyProvider } from './providers/CoolifyProvider';
import { DokployProvider } from './providers/DokployProvider';
import { RunCloudProvider } from './providers/RunCloudProvider';
import { ForgeProvider } from './providers/ForgeProvider';
import type {
  MigrationProvider,
  ProviderDetectionResult,
  DiscoveredItem,
  ScanProgress,
  ScanResult,
  DecommissionPlan,
  DecommissionStep,
} from './types';

export class MigrationScanEngine {
  private providers: BaseProvider[];

  constructor() {
    this.providers = [
      new RunCloudProvider(),
      new ForgeProvider(),
      new CoolifyProvider(),
      new DokployProvider(),
      new RawVpsProvider(), // Always last — fallback
    ];
  }

  async detectAndScan(migrationId: string, serverId: string): Promise<ScanResult> {
    // 1. Run all providers' detect() in parallel
    const detections = await Promise.allSettled(
      this.providers.map(p => p.detect(serverId, sshService))
    );

    // 2. Pick highest confidence
    let winner: BaseProvider = this.providers[this.providers.length - 1]; // RawVps fallback
    let winnerDetection: ProviderDetectionResult | null = null;
    let maxConfidence = 0;

    for (let i = 0; i < detections.length; i++) {
      const result = detections[i];
      if (result.status === 'fulfilled' && result.value.confidence > maxConfidence) {
        maxConfidence = result.value.confidence;
        winner = this.providers[i];
        winnerDetection = result.value;
      }
    }

    const warnings: string[] = [];
    const errors: string[] = [];

    // 3. Scan with winner
    const ctx: ProviderScanContext = {
      migrationId,
      serverId,
      sshService,
      emitProgress: (progress) => this.emitProgress(progress),
    };

    let items: DiscoveredItem[] = [];
    try {
      items = await winner.scan(ctx);
    } catch (err) {
      errors.push(`Scan failed for ${winner.displayName}: ${err instanceof Error ? err.message : String(err)}`);
    }

    // 4. If winner !== raw_vps, also scan with raw_vps for supplemental items
    if (winner.providerId !== 'raw_vps') {
      try {
        const rawVps = this.providers.find(p => p.providerId === 'raw_vps')!;
        const supplementalItems = await rawVps.scan(ctx);
        // Deduplicate by remoteKey
        const existingKeys = new Set(items.map(i => i.remoteKey));
        const newItems = supplementalItems.filter(i => !existingKeys.has(i.remoteKey));
        if (newItems.length > 0) {
          items.push(...newItems);
          warnings.push(`Found ${newItems.length} additional items not managed by ${winner.displayName}`);
        }
      } catch (err) {
        warnings.push(`Supplemental raw VPS scan failed: ${err instanceof Error ? err.message : String(err)}`);
      }
    }

    return {
      migrationId,
      provider: winner.providerId,
      providerVersion: winnerDetection?.version ?? null,
      items,
      warnings,
      errors,
    };
  }

  async getDecommissionPlan(provider: MigrationProvider, serverId: string): Promise<DecommissionPlan | null> {
    const providerInstance = this.providers.find(p => p.providerId === provider);
    if (!providerInstance) return null;
    return providerInstance.getDecommissionPlan(serverId, sshService);
  }

  async executeDecommissionStep(
    provider: MigrationProvider,
    serverId: string,
    step: DecommissionStep
  ): Promise<{ success: boolean; output: string }> {
    const providerInstance = this.providers.find(p => p.providerId === provider);
    if (!providerInstance) return { success: false, output: 'Provider not found' };
    return providerInstance.executeDecommissionStep(serverId, sshService, step);
  }

  private emitProgress(progress: ScanProgress): void {
    BrowserWindow.getAllWindows().forEach(w => {
      if (!w.isDestroyed()) w.webContents.send('migration:scanProgress', progress);
    });
  }
}
